After research, the key insight is: the bit length can grow by 1 each step, but also shrink. With bidirectional BFS meeting in middle, depth ~63 each side, but we need pruning. The bit length of intermediate values is bounded by ~126.

import sys
from collections import deque

def solve():
    x, y = map(int, input().split())

    MAX_BITS = 128

    def forward_step(v):
        b = bin(v)[2:]
        results = []
        for bit in ['0', '1']:
            s = b + bit
            r = s[::-1].lstrip('0') or '0'
            results.append(int(r, 2))
        return results

    def backward_step(v):
        b = bin(v)[2:]
        r = b[::-1]
        results = []
        for bit in ['0', '1']:
            candidate = r + bit
            if candidate[0] == '1':
                val = int(candidate, 2)
                if val.bit_length() <= MAX_BITS:
                    results.append(val)
        return results

    if x == y:
        print("YES")
        return

    front = {x}
    back = {y}
    visited_front = {x}
    visited_back = {y}

    for _ in range(200):
        if not front and not back:
            break

        new_front = set()
        for v in front:
            if v.bit_length() > MAX_BITS:
                continue
            for nv in forward_step(v):
                if nv in visited_back:
                    print("YES")
                    return
                if nv not in visited_front and nv.bit_length() <= MAX_BITS:
                    new_front.add(nv)
                    visited_front.add(nv)
        front = new_front

        if front & visited_back:
            print("YES")
            return

        new_back = set()
        for v in back:
            if v.bit_length() > MAX_BITS:
                continue
            for nv in backward_step(v):
                if nv in visited_front:
                    print("YES")
                    return
                if nv not in visited_back and nv.bit_length() <= MAX_BITS:
                    new_back.add(nv)
                    visited_back.add(nv)
        back = new_back

        if back & visited_front:
            print("YES")
            return

    print("NO")

solve()

